import AVFoundation
import Foundation

// MARK: - Zoom Control
extension CameraSessionManager {
    func getZoom() -> Double? {
        guard let device = self.currentDevice else { return nil }
        return Double(device.videoZoomFactor)  // originally CGFloat
    }

    func getMinZoom() -> Double? {
        if self.currentDevice == nil { return nil }
        // Fixed regardless of device.
        // https://developer.apple.com/documentation/avfoundation/avcapturedevice/2865754-minavailablevideozoomfactor
        return 1.0
    }

    func getMaxZoom() -> Double? {
        guard let device = self.currentDevice else { return nil }
        // Limit of optical zoom. Not digital zoom.
        // https://developer.apple.com/documentation/avfoundation/avcapturedevice/format/1624638-videozoomfactorupscalethreshold
        // 17 Pro(iOS 26.0.1) で zoom を 2.0 以上 & 低照度で紫色のフィルターがかかる問題があるため getMaxZoom を 1.99 でキャップ
        // videoZoomFactorUpscaleThreshold が 2.0 より大きい場合でも、zoom が 2.0 を越えるとこの減少が発生する
        // 15 Pro Max (iOS 26.0.1) ではこの問題は発生しないため ISP(Image Signal Processor) = 画像処理エンジンの影響だと思われる
        let threshold = Double(device.activeFormat.videoZoomFactorUpscaleThreshold)
        return min(threshold, 1.99)
    }

    func setZoom(zoom: Double) {
        guard let device = self.currentDevice else {
            self.messageText = "Changing zoom scale failed: No device available"
            return
        }

        do {
            try device.lockForConfiguration()
            device.videoZoomFactor = zoom
            device.unlockForConfiguration()

            self.messageText = "Changed zoom scale to \(zoom)"
        } catch {
            self.messageText =
                "Changing zoom scale failed: \(error.localizedDescription)"
        }
    }
}

