   285→  }
   286→
   287→  @override
   288→  void didChangeAppLifecycleState(AppLifecycleState state) {
   289→    if (state == AppLifecycleState.paused ||
   290→        state == AppLifecycleState.inactive ||
   291→        state == AppLifecycleState.detached) {
   292→      _saveCameraProfileToStorage();
   293→    }
   294→    super.didChangeAppLifecycleState(state);
   295→  }
   296→
   297→  void _saveCameraProfileToStorage() {
   298→    try {
   299→      if (state.focus != null && state.isFocusModeAuto == false) {
   300→        profileStorage.setCameraFocusValue(state.focus!);
   301→        profileStorage.setCameraAutoFocusMode(false);
   302→      }
   303→      if (state.isFocusModeAuto != null) {
   304→        profileStorage.setCameraAutoFocusMode(state.isFocusModeAuto!);
   305→      }
   306→    } catch (e, stacktrace) {
   307→      _logger.e('Failed to save camera profile to storage',
   308→          ex: e, stacktrace: stacktrace);
   309→    }
   310→  }
   311→
   312→  void _startParamUpdateTimer() {
   313→    try {
   314→      if (_paramUpdateTimer != null) return; // 多重起動防止
   315→      _paramUpdateTimer =
   316→          Timer.periodic(const Duration(milliseconds: 500), (_) async {
   317→        final (
   318→          iso,
   319→          shutterSpeed,
   320→          focus,
   321→          zoom,
   322→          longsideAngleOfView,
   323→          focusMangifierEnabled
   324→        ) = await (
   325→          getISO(),
   326→          getShutterSpeed(),
   327→          getFocus(),
   328→          getZoom(),
   329→          getLongsideAngleOfView(),
   330→          getFocusMagnifierEnabled(),
   331→        ).wait;
   332→        if (iso != state.iso ||
   333→            focus != state.focus ||
   334→            shutterSpeed != state.shutterSpeed ||
   335→            zoom != state.zoom ||
   336→            longsideAngleOfView != state.longsideAngleOfView ||
   337→            focusMangifierEnabled != state.focusMagnifierEnabled) {
   338→          state = state.copyWith(
   339→            iso: iso,
   340→            shutterSpeed: shutterSpeed,
   341→            focus: focus,
   342→            zoom: zoom,
   343→            longsideAngleOfView: longsideAngleOfView,
   344→            focusMagnifierEnabled: focusMangifierEnabled,
   345→          );
   346→        }
   347→      });
   348→    } catch (e, stacktrace) {
   349→      _logger.e('Failed to start param update timer',
   350→          ex: e, stacktrace: stacktrace);
   351→    }
   352→  }
   353→
   354→  Future<String?> initializeRecordingDirectory(
   355→    String sessionId,
   356→    DateTime sessionCreatedAt,
   357→  ) async {
   358→    try {
   359→      // sessionDate を使って recordingDirectory を組み立てる
   360→      final sessionDate = sessionCreatedAt
   361→          .toUtc() // assumes UTC
   362→          .toIso8601String()
   363→          .split('T')
   364→          .first;
   365→      final baseDir = await LocalVideoData.getBaseDirectory();
   366→      _currentSession = RecordingSession(
   367→        sessionId: sessionId,
   368→        directory: join(baseDir, 'videos', '$sessionDate.$sessionId'),
   369→      );
   370→      return _currentSession!.directory;
   371→    } catch (e, stacktrace) {
   372→      _logger.e(
   373→        'Failed to init recording directory',
   374→        ex: e,
   375→        stacktrace: stacktrace,
   376→      );
   377→      return null;
   378→    }
   379→  }
   380→
   381→  Future<int?> configureSession(VoidCallback? onVolumeKeyPressed) async {
   382→    try {
   383→      // The `knowhere_configurable_camera` library does not manage camera permission.
   384→      // So this project leverages `permission_handler` library to handle camera permission.
   385→      final isPermissionGranted = await Permission.camera.request().isGranted;
   386→      if (!isPermissionGranted) {
   387→        _logger.w('Camera permission is not granted');
   388→        return null;
   389→      }
   390→
   391→      _logger.i('Camera permission is granted');
   392→
   393→      final cameraId = await cameraAPI.configureSession(
   394→        onVolumeKeyPressed: onVolumeKeyPressed,
   395→      );
   396→
   397→      _logger.i('Camera session configured with ID: $cameraId');
   398→
   399→      // 主要なカメラパラメータを一括取得してstateを更新
   400→      await _updateNativeParameters();
   401→
   402→      _logger.i('Camera parameters updated');
   403→
   404→      if (isIos) {
   405→        await _setPreferences();
   406→        _logger.i('Camera preferences set');
   407→      } else {
   408→        await cameraAPI.setFocusModeToAuto();
   409→        if (state.isStabilizationAvailable == true) {
   410→          await setStabilizationModeOn();
   411→        }
   412→      }
   413→
   414→      if (!_timerStarted) {
   415→        _startParamUpdateTimer();
   416→        _timerStarted = true;
   417→      }
   418→
