   765→
   766→      final deviceInfo = DeviceInfoPlugin();
   767→      final device = platform.isAndroid
   768→          ? (await deviceInfo.androidInfo).model
   769→          : (await deviceInfo.iosInfo).utsname.fixedProductName();
   770→
   771→      final localVideoListController =
   772→          ref.read(localVideoListControllerProvider.notifier);
   773→      LocalVideoData? newData;
   774→
   775→      final teamId = profileStorage.getTeamId()!;
   776→
   777→      // NOTE: The method cameraAPI.stopRecording returns before completes saving a video file.
   778→      // TODO: Refactor knowhere_configurable_camera to wait completing.
   779→      await Future.delayed(const Duration(milliseconds: 500), () async {
