   781→          sessionId: _currentSession!.sessionId,
   782→          teamId: teamId,
   783→          filePath: _currentSession!.recordingFilePath!,
   784→          analyzeType: state.analysisType.value,
   785→          unit: unit,
   786→          focalLengthIn35mmEquivalent: null,
   787→          longsideAngleOfView: longsideAngleOfView!,
   788→          accX: accX,
   789→          accY: accY,
   790→          accZ: accZ,
   791→          lens: lens?.description,
   792→          cameraMode:
   793→              '${extendedZoomType == null ? '-' : extendedZoomType.name}+${state.cameraMode == null ? '-' : state.cameraMode!.name}${_isAutoExposure ? ' (AE)' : ''}',
   794→          focus: focus,
   795→          isAutoFocus: isAutoFocus,
   796→          zoom: zoom,
   797→          iso: iso,
   798→          shutterSpeed: shutterSpeed,
   799→          device: device,
   800→        );
   801→      });
   802→
   803→      _currentSession!.recordingFilePath = null;
   804→
   805→      return newData!;
   806→    } catch (e, stacktrace) {
