  1205→  Future<void> setExtendedZoomType(ExtendedZoomType extendedZoomType) async {
  1206→    try {
  1207→      int targetLensIndex;
  1208→      double targetZoom;
  1209→
  1210→      switch (extendedZoomType) {
  1211→        case ExtendedZoomType.superZoom:
  1212→          // Telephoto × max zoom
  1213→          if (state.telephotoLensList.isEmpty) {
  1214→            throw Exception('Telephoto lens not available for superZoom');
  1215→          }
  1216→          targetLensIndex = state.telephotoLensList.first.index;
  1217→          targetZoom = state.maxZoom ?? CameraState.defaultMaxZoom;
  1218→          break;
  1219→        case ExtendedZoomType.zoom:
  1220→          // Telephoto × min zoom
  1221→          if (state.telephotoLensList.isEmpty) {
  1222→            throw Exception('Telephoto lens not available for zoom');
  1223→          }
  1224→          targetLensIndex = state.telephotoLensList.first.index;
  1225→          targetZoom = state.minZoom ?? CameraState.defaultMinZoom;
  1226→          break;
  1227→        case ExtendedZoomType.wide:
  1228→          // WideAngle × max zoom
  1229→          if (state.wideAngleLensList.isEmpty) {
  1230→            throw Exception('WideAngle lens not available for wide');
  1231→          }
  1232→          targetLensIndex = state.wideAngleLensList.first.index;
  1233→          targetZoom = state.maxZoom ?? CameraState.defaultMaxZoom;
  1234→          break;
  1235→        case ExtendedZoomType.superWide:
  1236→          // WideAngle × min zoom
  1237→          if (state.wideAngleLensList.isEmpty) {
  1238→            throw Exception('WideAngle lens not available for superWide');
  1239→          }
  1240→          targetLensIndex = state.wideAngleLensList.first.index;
  1241→          targetZoom = state.minZoom ?? CameraState.defaultMinZoom;
  1242→          break;
  1243→      }
  1244→
  1245→      // Save to profileStorage
  1246→      profileStorage.setCameraExtendedZoomType(extendedZoomType);
  1247→
  1248→      // Apply settings (lens first, then zoom)
  1249→      await setLensIndex(targetLensIndex);
  1250→      await setZoom(targetZoom);
  1251→
  1252→      // Update state
  1253→      state = state.copyWith(extendedZoom: extendedZoomType);
  1254→    } catch (e, stacktrace) {
  1255→      _logger.e('Failed to set extended zoom type',
  1256→          ex: e, stacktrace: stacktrace);
  1257→      rethrow;
  1258→    }
  1259→  }
