  1261→  Future<String> setLensIndex(int index) async {
  1262→    try {
  1263→      final message = await cameraAPI.setLensIndex(index);
  1264→      await _updateNativeParameters();
  1265→
  1266→      final lensList = state.lensList;
  1267→      if (index >= 0 && index < lensList!.length) {
  1268→        state = state.copyWith(lens: lensList[index]);
  1269→      }
  1270→      // Stabilization mode is sometimes turned off by iOS when it changes its lens.
  1271→      if (state.isStabilizationAvailable == true) {
  1272→        await setStabilizationModeOn();
  1273→      }
  1274→
  1275→      setUpAutoExposureObserver();
  1276→
  1277→      return message;
