  1304→  Future<void> setCameraModeAuto() async {
  1305→    try {
  1306→      if (!isTestEnvironment && !platform.isIos) return;
  1307→
  1308→      state = state.copyWith(cameraMode: CameraMode.auto);
  1309→
  1310→      final savedExtendedZoomType = profileStorage.getCameraExtendedZoomType();
  1311→      final extendedZoomType = savedExtendedZoomType ??
  1312→          (state.isTelephotoAvailable == true
  1313→              ? ExtendedZoomType.zoom
  1314→              : ExtendedZoomType.wide);
  1315→
  1316→      final formatFullHD60FPS = await getBestFormat();
  1317→      assert(formatFullHD60FPS != null);
  1318→      await setFormatIndex(formatFullHD60FPS!.index);
  1319→
  1320→      // format 変更後にzoomを設定
  1321→      await setExtendedZoomType(extendedZoomType);
  1322→
  1323→      // Set shutter speed
  1324→      await setShutterSpeed(4000);
  1325→
  1326→      // Set Initial ISO to 1000
  1327→      await setISO(1000);
  1328→      setUpAutoExposureObserver();
  1329→    } catch (e, stacktrace) {
  1330→      _logger.e('Failed to set bright mode', ex: e, stacktrace: stacktrace);
  1331→      rethrow;
  1332→    }
