  1346→  Future<void> setAnalysisType(AnalysisType analysisType) async {
  1347→    try {
  1348→      // Check if current extended zoom is SuperWide and new analysis type is pitching-related
  1349→      final currentExtendedZoom = state.extendedZoom;
  1350→      final isPitchingRelated = analysisType == AnalysisType.pitching ||
  1351→          analysisType == AnalysisType.both ||
  1352→          analysisType == AnalysisType.pitchingAll;
  1353→
  1354→      state = state.copyWith(analysisType: analysisType);
  1355→      profileStorage.setCameraAnalysisType(analysisType.value);
  1356→
  1357→      // If currently in SuperWide mode and switching to pitching-related analysis,
  1358→      // automatically switch to Wide mode
  1359→      if (currentExtendedZoom == ExtendedZoomType.superWide &&
  1360→          isPitchingRelated) {
  1361→        await setExtendedZoomType(ExtendedZoomType.wide);
  1362→      }
  1363→    } catch (e, stacktrace) {
  1364→      _logger.e('Failed to set analysis type', ex: e, stacktrace: stacktrace);
  1365→      rethrow;
  1366→    }
  1367→  }
