// Package imports:
import 'package:flutter_test/flutter_test.dart';
import 'package:knowhere_configurable_camera/knowhere_configurable_camera.dart';

// Project imports:
import 'package:baseball_detector_flutter/controllers/camera_controller.dart';
import 'package:baseball_detector_flutter/data/models/enums/extended_zoom_type.dart';

void main() {
  group('determineExtendedZoomType', () {
    test('should return tele when telephoto lens with max zoom', () {
      final lens = Lens(0, 'Telephoto');

      final result = ExtendedZoomType.fromLensAndZoom(
        currentLens: lens,
        currentZoom: CameraState.defaultMaxZoom,
        maxZoom: CameraState.defaultMaxZoom,
        minZoom: CameraState.defaultMinZoom,
      );

      expect(result, ExtendedZoomType.superZoom);
    });

    test('should return standard when telephoto lens with min zoom', () {
      final lens = Lens(0, 'Telephoto');

      final result = ExtendedZoomType.fromLensAndZoom(
        currentLens: lens,
        currentZoom: CameraState.defaultMinZoom,
        maxZoom: CameraState.defaultMaxZoom,
        minZoom: CameraState.defaultMinZoom,
      );

      expect(result, ExtendedZoomType.zoom);
    });

    test('should return wide when wide angle lens with max zoom', () {
      final lens = Lens(0, 'WideAngle');

      final result = ExtendedZoomType.fromLensAndZoom(
        currentLens: lens,
        currentZoom: CameraState.defaultMaxZoom,
        maxZoom: CameraState.defaultMaxZoom,
        minZoom: CameraState.defaultMinZoom,
      );

      expect(result, ExtendedZoomType.wide);
    });

    test('should return null when telephoto lens with intermediate zoom', () {
      final lens = Lens(0, 'Telephoto');

      final result = ExtendedZoomType.fromLensAndZoom(
        currentLens: lens,
        currentZoom: 1.5, // intermediate zoom
        maxZoom: CameraState.defaultMaxZoom,
        minZoom: CameraState.defaultMinZoom,
      );

      expect(result, null);
    });

    test('should return superWide when wide angle lens with min zoom', () {
      final lens = Lens(0, 'WideAngle');

      final result = ExtendedZoomType.fromLensAndZoom(
        currentLens: lens,
        currentZoom: CameraState.defaultMinZoom,
        maxZoom: CameraState.defaultMaxZoom,
        minZoom: CameraState.defaultMinZoom,
      );

      expect(result, ExtendedZoomType.superWide);
    });

    test('should return null for non-telephoto/wide angle lens', () {
      final lens = Lens(0, 'UltraWideAngle');

      final result = ExtendedZoomType.fromLensAndZoom(
        currentLens: lens,
        currentZoom: CameraState.defaultMaxZoom,
        maxZoom: CameraState.defaultMaxZoom,
        minZoom: CameraState.defaultMinZoom,
      );

      expect(result, null);
    });
  });
}

