    17→// レンズ × zoom でカメラの倍率を表示する
    18→// Telephoto レンズが利用可能な iPhone の Pro 系統のみで使用する
    19→// - superZoom : Telephoto × zoom 2.0x
    20→// - zoom      : Telephoto × zoom 1.0x
    21→// - wide      : WideAngle × zoom 2.0x
    22→// - superWide : WideAngle × zoom 1.0x
    23→class ExtendedZoomText extends HookConsumerWidget {
    24→  const ExtendedZoomText({
    25→    required this.orientation,
    26→    required this.selected,
    27→    super.key,
    28→  });
    29→
    30→  final ValueNotifier<NativeDeviceOrientation> orientation;
    31→  final ValueNotifier<CameraConfigurationDisplayType?> selected;
    32→
    33→  @override
    34→  Widget build(BuildContext context, WidgetRef ref) {
    35→    final extendedZoomTypeName = useExtendedZoomTypeName(hasBlank: true);
    36→    final selectedType = useValueListenable(selected);
    37→    final lens =
    38→        ref.watch(cameraControllerProvider.select((value) => value.lens));
    39→    final zoom =
    40→        ref.watch(cameraControllerProvider.select((value) => value.zoom));
