// Flutter imports:
import 'package:flutter/material.dart';

// Package imports:
import 'package:flutter_hooks/flutter_hooks.dart';
import 'package:hooks_riverpod/hooks_riverpod.dart';
import 'package:native_device_orientation/native_device_orientation.dart';

// Project imports:
import 'package:baseball_detector_flutter/controllers/camera_controller.dart';
import 'package:baseball_detector_flutter/data/models/enums/extended_zoom_type.dart';
import 'package:baseball_detector_flutter/views/pages/home/sessions/session_details/recording/components/camera_configuration_display_view.dart';
import 'package:baseball_detector_flutter/views/pages/home/sessions/session_details/recording/components/camera_setting_button.dart';
import 'package:baseball_detector_flutter/views/pages/home/sessions/session_details/recording/components/recommended_distance_text.dart';
import 'package:baseball_detector_flutter/views/pages/home/sessions/session_details/recording/hooks/use_extended_zoom_type_name.dart';

// レンズ × zoom でカメラの倍率を表示する
// Telephoto レンズが利用可能な iPhone の Pro 系統のみで使用する
// - superZoom : Telephoto × zoom 2.0x
// - zoom      : Telephoto × zoom 1.0x
// - wide      : WideAngle × zoom 2.0x
// - superWide : WideAngle × zoom 1.0x
class ExtendedZoomText extends HookConsumerWidget {
  const ExtendedZoomText({
    required this.orientation,
    required this.selected,
    super.key,
  });

  final ValueNotifier<NativeDeviceOrientation> orientation;
  final ValueNotifier<CameraConfigurationDisplayType?> selected;

  @override
  Widget build(BuildContext context, WidgetRef ref) {
    final extendedZoomTypeName = useExtendedZoomTypeName(hasBlank: true);
    final selectedType = useValueListenable(selected);
    final lens =
        ref.watch(cameraControllerProvider.select((value) => value.lens));
    final zoom =
        ref.watch(cameraControllerProvider.select((value) => value.zoom));
    final maxZoom =
        ref.watch(cameraControllerProvider.select((value) => value.maxZoom));
    final minZoom =
        ref.watch(cameraControllerProvider.select((value) => value.minZoom));

    if (lens == null || zoom == null || maxZoom == null || minZoom == null) {
      return const SizedBox.shrink();
    }

    final currentExtendedZoomType = ExtendedZoomType.fromLensAndZoom(
      currentLens: lens,
      currentZoom: zoom,
      maxZoom: maxZoom,
      minZoom: minZoom,
    );

    return CameraSettingButton(
      title: extendedZoomTypeName(currentExtendedZoomType),
      subWidget: RecommendedDistanceText(),
      orientation: orientation,
      onPressed: () {
        selected.value =
            selectedType != CameraConfigurationDisplayType.extendedZoom
                ? CameraConfigurationDisplayType.extendedZoom
                : null;
      },
    );
  }
}
